const rows = items.map(i => i.json);

const isAvailable = (v) => {
  const s = (v ?? '').toString().toLowerCase().trim();
  return ['true','yes','1','available','in stock','instock'].includes(s);
};

const available = rows.filter(r => isAvailable(r.availability));

if (available.length === 0) {
  return [{ json: { message: "No products/services are currently available.\nSend /catalog later or ask me about a specific service." } }];
}

const lines = available.slice(0, 12).map((r, idx) => {
  const price = r.price ? `${r.price} ${r.currency || ''}`.trim() : 'Price: N/A';
  const duration = r.service_duration_minutes ? ` • ${r.service_duration_minutes} min` : '';
  const desc = (r.description || '').toString().trim();
  const shortDesc = desc.length > 90 ? desc.slice(0, 90) + '…' : desc;

  return `*${idx + 1}. ${r.name}*\nID: \`${r.product_id}\`\n${shortDesc}\n${price}${duration}`;
});

const text =
  `✅ *Available items (${available.length})*\n` +
  `Reply with: *book <ID>*  (example: \`book P001\`)\n\n` +
  lines.join('\n\n');

return [{ json: { message: text } }];

const text = ($node["TG Trigger - Incoming Message"].json.message.text || "").trim();

// Accept formats: "book P001" or "/book P001"
const match = text.match(/^(\/?book)\s+([A-Za-z0-9_-]+)\s*$/i);

if (!match) {
  return [{
    json: {
      ok: false,
      error: "Invalid format. Use: book P001",
    }
  }];
}

return [{
  json: {
    ok: true,
    product_id: match[2].toUpperCase(),
  }
}];

const now = new Date().toISOString();
const bookingId = "BKG-" + Date.now();

return [{
  json: {
    booking_id: bookingId,
    timestamp: now, // if your sheet has "timestamp" column
    chat_id: $json.chat_id || "", // if your sheet has "chat_id" column

    telegram_user_id: $json.telegram_user_id || "",
    telegram_username: $node["SET - Normalize Input"].json.username || "",

    customer_name: $json.draft_customer_name || "",
    email: $json.draft_email || "",

    product_id: $json.draft_product_id || "",
    product_name: "",

    service_name: $json.product_name || "",

    quantity: $json.quantity || 1,

    preferred_date: $json.draft_date || "",
    preferred_time: $json.draft_time || "",

    status: "CONFIRMED",
    created_at: now,
    notes: ""
  }
}];

// Create a short unique booking id like: BK-20260306-7F3KQ2
const now = new Date();
const y = now.getFullYear();
const m = String(now.getMonth() + 1).padStart(2, '0');
const d = String(now.getDate()).padStart(2, '0');

const rand = Math.random().toString(36).slice(2, 8).toUpperCase();

return [{
  json: {
    ...$json,
    booking_id: `BK-${y}${m}${d}-${rand}`,
    timestamp: now.toISOString(),
    status: $json.status || "Booked",
  }
}];

