const content = $json.choices?.[0]?.message?.content ?? "{}";
const parsed = JSON.parse(content);

// merge: keep telegram_user_id, chat_id, username, etc.
return [{
  json: {
    ...$node["SET - Normalize Input"].json,
    ...parsed
  }
}];

const session = $node["Session Found?"].json; // session row (or empty)
const ai = $node["JS - Parse Groq JSON"].json;

const state = (session && session.state) ? String(session.state) : "idle";
const intent = String(ai.intent || "unknown").toLowerCase();

let route = "fallback";
if (intent === "catalog") route = "catalog";
else if (intent === "book" || state.startsWith("collect_") || state === "confirm") route = "booking";
else if (intent === "browse") route = "browse";
else if (intent === "help") route = "help";
else if (intent === "cancel") route = "cancel";

return [{
  json: {
    ...ai,
    route,
    state,
    session_row_number: session?.row_number ?? null,
    telegram_user_id: session?.telegram_user_id ?? null,
    chat_id: session?.chat_id ?? null,
  }
}];

return [{
  json: {
    ...$json,
    session_row_number: Number($json.session_row_number || 0),
    telegram_user_id: String($json.telegram_user_id || ""),
    chat_id: String($json.chat_id || ""),
  }
}];

const text = ($node["SET - Normalize Input"].json.text || "").trim();
const state = $json.state || "idle";

// Start from current draft values
const out = { ...$json };

// If user typed /cancel anytime
if (text.toLowerCase() === "/cancel") {
  out.state = "idle";
  out.route = "cancel";
  out.draft_customer_name = "";
  out.draft_email = "";
  out.draft_product_id = out.draft_product_id || "";
  return [{ json: out }];
}

// Capture based on what we were collecting
if (state === "collect_name") {
  out.draft_customer_name = text;
  out.state = "collect_email";
}

if (state === "collect_email") {
  out.draft_email = text;
  out.state = "confirm";
}

if (state === "confirm") {
  out.confirm_text = text.toLowerCase();
}

return [{ json: out }];
